#include <stdio.h>

int main() {
    int T, X;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d", &X);
        int r = X % 10;
        int rounded;
        if (r < 5) {
            rounded = X - r;
        } else if (r > 5) {
            rounded = X + (10 - r);
        } else { // r == 5
            rounded = X + 5;
        }
        int change = 100 - rounded;
        printf("%d\n", change);
    }
    return 0;
}

