#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    idx = 1
    for _ in range(t):
        x = int(data[idx]); idx += 1
        r = x % 10
        if r < 5:
            rounded = x - r
        elif r > 5:
            rounded = x + (10 - r)
        else:  # r == 5
            rounded = x + 5
        out.append(str(100 - rounded))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

